function solve(nums, queries) {
    // Precompute popcount-depth for numbers up to 1e15
    const depthMap = new Map();
    depthMap.set(0, 0);
    depthMap.set(1, 0);

    function getPopcount(x) {
        let count = 0;
        while (x > 0) {
            count += x & 1;
            x >>>= 1;
        }
        return count;
    }

    function computeDepth(x) {
        if (depthMap.has(x)) {
            return depthMap.get(x);
        }
        const pop = getPopcount(x);
        const depth = 1 + computeDepth(pop);
        depthMap.set(x, depth);
        return depth;
    }

    // Precompute depths for all nums initially
    const depths = new Array(nums.length);
    for (let i = 0; i < nums.length; i++) {
        depths[i] = computeDepth(nums[i]);
    }

    const answer = [];
    for (const query of queries) {
        if (query[0] === 1) {
            const [_, l, r, k] = query;
            let count = 0;
            for (let i = l; i <= r; i++) {
                if (depths[i] === k) {
                    count++;
                }
            }
            answer.push(count);
        } else if (query[0] === 2) {
            const [_, idx, val] = query;
            nums[idx] = val;
            depths[idx] = computeDepth(val);
        }
    }
    return answer;
}

