import scala.collection.mutable

def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  val depthMap = mutable.Map[Long, Int]()
  depthMap.put(0L, 0)
  depthMap.put(1L, 0)

  def getPopcount(x: Long): Int = {
    var count = 0
    var n = x
    while (n > 0) {
      count += (n & 1).toInt
      n = n >>> 1
    }
    count
  }

  def computeDepth(x: Long): Int = {
    depthMap.getOrElse(x, {
      val pop = getPopcount(x)
      val depth = 1 + computeDepth(pop)
      depthMap.put(x, depth)
      depth
    })
  }

  val depths = new Array[Int](nums.length)
  for (i <- nums.indices) {
    depths(i) = computeDepth(nums(i))
  }

  val answer = mutable.ArrayBuffer[Long]()
  for (query <- queries) {
    if (query(0) == 1) {
      val l = query(1).toInt
      val r = query(2).toInt
      val k = query(3).toInt
      var count = 0L
      for (i <- l to r) {
        if (depths(i) == k) {
          count += 1
        }
      }
      answer += count
    } else if (query(0) == 2) {
      val idx = query(1).toInt
      val value = query(2)
      nums(idx) = value
      depths(idx) = computeDepth(value)
    }
  }
  answer.toArray
}
